  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        ...meta,
        label: "PulseBoard",
        docsPath: "/channels/pulseboard",
        blurb: "Connect to PulseBoard bulletin board messaging.",
      },
      capabilities: {
        chatTypes: ["direct", "group"],
        media: false,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      config: {
        listAccountIds: (_cfg) => [],
        resolveAccount: ({ accountId }) => ({
          accountId,
          boardUrl: "",
          username: "",
          configured: false,
        }),
